import React, { useState, useEffect } from 'react';
import { useHistory } from 'react-router-dom';
import { updateComplaint } from '../services/api'; // Ensure this is imported
import '../styles/style.css';

function ComplaintDetail({ complaint }) {
  const [message, setMessage] = useState(complaint?.message || ''); // Store current message
  const [error, setError] = useState('');
  const history = useHistory();

  const handleUpdate = async (e) => {
    e.preventDefault();

    if (!message.trim()) {
      setError('Message cannot be empty');
      return;
    }

    try {
      const token = localStorage.getItem('token');
      await updateComplaint(complaint._id, { message }, token); // Send message update to backend
      history.push('/complaints'); // Redirect to the complaints list page after update
    } catch (err) {
      setError('Failed to update complaint');
    }
  };

  return (
    <div className="complaint-detail-container">
      {complaint ? (
        <div className="complaint-card">
          <h2>{complaint.title}</h2>
          <p><strong>Description:</strong> {complaint.description}</p>
          <p><strong>Status:</strong> {complaint.status}</p>
          <p><strong>Created At:</strong> {new Date(complaint.createdAt).toLocaleString()}</p>
          <p><strong>Updated At:</strong> {new Date(complaint.updatedAt).toLocaleString()}</p>

          {complaint.image && (
            <div className="complaint-image">
              <img
                src={complaint.image}
                alt="Complaint"
                className="complaint-thumbnail"
              />
            </div>
          )}

          {complaint.student && (
            <p><strong>Filed By:</strong> {complaint.student.email} ({complaint.student.role})</p>
          )}

          {/* Update message section */}
          <h3>Update Complaint Message</h3>
          <form onSubmit={handleUpdate}>
            <textarea
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              rows="4"
              placeholder="Enter your updated message here"
            />
            {error && <p className="error">{error}</p>}
            <button type="submit">Update Message</button>
          </form>

          {/* Chat Section */}
          {complaint.chat?.length > 0 && (
            <div className="chat-section">
              <h4>Chat History</h4>
              <ul>
                {complaint.chat.map((msg, index) => (
                  <li key={index}>
                    <strong>{msg.user?.email || 'Unknown'}:</strong> {msg.message}
                    <br />
                    <small>{new Date(msg.date).toLocaleString()}</small>
                  </li>
                ))}
              </ul>
            </div>
          )}
        </div>
      ) : (
        <p>Loading complaint...</p>
      )}
    </div>
  );
}

export default ComplaintDetail;
